SELECT

FROM building_department_assignments a
LEFT JOIN dormitory_buildings b ON a.building_id = b.id AND b.deleted = 0
LEFT JOIN org_units o ON a.org_unit_id = o.id AND o.deleted = 0

    a.deleted = 0

        AND a.building_id = #{buildingId}


        AND a.org_unit_id = #{orgUnitId}


        AND a.status = #{status}


ORDER BY b.building_name ASC, a.priority DESC, a.floor_start ASC

SELECT COUNT(*) FROM building_department_assignments WHERE building_id = #{buildingId} AND org_unit_id = #{orgUnitId} AND deleted = 0 AND status = 1
AND id != #{excludeId}
AND ( -- 全楼分配与任何分配冲突 (floor_start IS NULL AND floor_end IS NULL) OR (#{floorStart} IS NULL AND #{floorEnd} IS NULL) -- 楼层范围重叠检查 OR ( COALESCE(floor_start, 1) <= COALESCE(#{floorEnd}, 999) AND COALESCE(floor_end, 999) >= COALESCE(#{floorStart}, 1) ) )
